import * as vscode from 'vscode';
import {
    ArchitectureDriftReport,
    StitchJudgement,
    TraceabilityMatrix,
} from './types';
import { sendLlmRequest } from '../lm/chatModelHelper';
import {
    buildDriftAnalysisUserPrompt,
    STITCH_JUDGE_SYSTEM_PROMPT,
    buildStitchJudgeUserPrompt,
    ANTI_CORRUPTION_SYSTEM_PROMPT,
    buildAntiCorruptionUserPrompt,
    DRIFT_ANALYSIS_SYSTEM_PROMPT,
    TRACEABILITY_SYSTEM_PROMPT,
    buildTraceabilityUserPrompt,
} from '../lm/prompts';

/**
 * Architecture stitching judge — compares ArchiMate intent against
 * implementation UML and returns a structured verdict.
 */
export class StitchJudge {

    private static readonly ANALYSIS_TOKEN_BUDGET = 4096;

    /**
     * Full stitching check: does the implementation UML match the intent?
     */
    async judge(
        archiMateIntent: string,
        implementationUml: string,
        token: vscode.CancellationToken,
    ): Promise<StitchJudgement> {
        return this.runAnalysis(
            STITCH_JUDGE_SYSTEM_PROMPT,
            buildStitchJudgeUserPrompt(archiMateIntent, implementationUml),
            token,
            raw => this.parseJudgement(raw),
        );
    }

    /**
     * Anti-corruption check for /evolve: ensure the new implementation
     * aligns with the current target intent without polluting unrelated domains.
     */
    async antiCorruptionCheck(
        previousUml: string,
        newUml: string,
        currentIntent: string,
        driftReport: string | undefined,
        token: vscode.CancellationToken,
    ): Promise<StitchJudgement> {
        return this.runAnalysis(
            ANTI_CORRUPTION_SYSTEM_PROMPT,
            buildAntiCorruptionUserPrompt(previousUml, newUml, currentIntent, driftReport),
            token,
            raw => this.parseJudgement(raw),
        );
    }

    /**
     * Build a traceability matrix mapping intent components to code elements.
     */
    async buildTraceabilityMatrix(
        archiMateIntent: string,
        implementationUml: string,
        token: vscode.CancellationToken,
    ): Promise<TraceabilityMatrix> {
        return this.runAnalysis(
            TRACEABILITY_SYSTEM_PROMPT,
            buildTraceabilityUserPrompt(archiMateIntent, implementationUml),
            token,
            raw => this.parseTraceability(raw),
        );
    }

    async analyseDrift(
        archiMateIntent: string,
        implementationUml: string,
        traceabilityMatrix: TraceabilityMatrix,
        token: vscode.CancellationToken,
    ): Promise<ArchitectureDriftReport> {
        return this.runAnalysis(
            DRIFT_ANALYSIS_SYSTEM_PROMPT,
            buildDriftAnalysisUserPrompt(
                archiMateIntent,
                implementationUml,
                JSON.stringify(traceabilityMatrix, null, 2),
            ),
            token,
            raw => this.parseDriftReport(raw),
        );
    }

    // ── Private parsing helpers ──────────────────────────────────────────

    private async runAnalysis<T>(
        systemPrompt: string,
        userPrompt: string,
        token: vscode.CancellationToken,
        parser: (raw: string) => T,
    ): Promise<T> {
        const raw = await sendLlmRequest(
            systemPrompt,
            userPrompt,
            token,
            StitchJudge.ANALYSIS_TOKEN_BUDGET,
        );
        return parser(raw);
    }

    private cleanJsonResponse(raw: string): string {
        return raw.replace(/```json?\s*/g, '').replace(/```/g, '').trim();
    }

    private parseJudgement(raw: string): StitchJudgement {
        try {
            const cleaned = this.cleanJsonResponse(raw);
            const parsed = JSON.parse(cleaned);
            return {
                verdict: parsed.verdict === 'pass' ? 'pass' : 'fail',
                violations: Array.isArray(parsed.violations)
                    ? parsed.violations.map((v: Record<string, unknown>) => ({
                        intentComponent: String(v.intentComponent ?? ''),
                        codeElement: String(v.codeElement ?? ''),
                        description: String(v.description ?? ''),
                        suggestedFix: String(v.suggestedFix ?? ''),
                    }))
                    : [],
                reasoning: String(parsed.reasoning ?? ''),
            };
        } catch {
            return {
                verdict: 'fail',
                violations: [],
                reasoning: `Failed to parse judge response: ${raw.slice(0, 500)}`,
            };
        }
    }

    private parseTraceability(raw: string): TraceabilityMatrix {
        try {
            const cleaned = this.cleanJsonResponse(raw);
            const parsed = JSON.parse(cleaned);
            return {
                entries: Array.isArray(parsed.entries)
                    ? parsed.entries.map((e: Record<string, unknown>) => ({
                        intentComponent: String(e.intentComponent ?? ''),
                        codeElements: Array.isArray(e.codeElements) ? e.codeElements.map(String) : [],
                        confidence: Number(e.confidence ?? 0),
                        rationale: String(e.rationale ?? ''),
                    }))
                    : [],
                generatedAt: new Date(),
            };
        } catch {
            return { entries: [], generatedAt: new Date() };
        }
    }

    private parseDriftReport(raw: string): ArchitectureDriftReport {
        try {
            const cleaned = this.cleanJsonResponse(raw);
            const parsed = JSON.parse(cleaned);
            const driftScoreRaw = Number(parsed.driftScore ?? 1);
            return {
                summary: String(parsed.summary ?? ''),
                overallStatus: parsed.overallStatus === 'aligned'
                    ? 'aligned'
                    : parsed.overallStatus === 'minor-drift'
                        ? 'minor-drift'
                        : 'major-drift',
                driftScore: Number.isFinite(driftScoreRaw)
                    ? Math.min(1, Math.max(0, driftScoreRaw))
                    : 1,
                deviations: Array.isArray(parsed.deviations)
                    ? parsed.deviations.map((item: Record<string, unknown>) => ({
                        intentComponent: String(item.intentComponent ?? ''),
                        codeElements: Array.isArray(item.codeElements) ? item.codeElements.map(String) : [],
                        category: String(item.category ?? 'other'),
                        severity: item.severity === 'low'
                            ? 'low'
                            : item.severity === 'medium'
                                ? 'medium'
                                : 'high',
                        description: String(item.description ?? ''),
                        impact: String(item.impact ?? ''),
                        recommendation: String(item.recommendation ?? ''),
                    }))
                    : [],
                recommendations: Array.isArray(parsed.recommendations)
                    ? parsed.recommendations.map(String)
                    : [],
                generatedAt: new Date(),
            };
        } catch {
            return {
                summary: `Failed to parse drift analysis response: ${raw.slice(0, 500)}`,
                overallStatus: 'major-drift',
                driftScore: 1,
                deviations: [],
                recommendations: [],
                generatedAt: new Date(),
            };
        }
    }
}

src/engine/types.ts:
import * as vscode from 'vscode';

// ============================================================================
// 1. Semantic UML Engine — Input / Output Contracts
// ============================================================================

/** A container-level code symbol (class, interface, module, enum) enriched with LSP-derived topology. */
export interface CodeSymbolNode {
    /** Fully-qualified symbol name (e.g. `OrderService`). */
    name: string;
    /** The kind reported by VS Code (class, interface, module, enum, struct). */
    kind: vscode.SymbolKind;
    /** File URI where the symbol is defined. */
    uri: vscode.Uri;
    /** Range within the file. */
    range: vscode.Range;
    /** Aggregated outgoing calls from all members, elevated to container names. */
    callees: string[];
    /** Aggregated incoming callers to all members, elevated to container names. */
    callers: string[];
    /** Lightweight code skeleton — signatures only, method bodies removed. */
    skeleton: string;
    /** Names of direct members (methods, properties) within this container. */
    memberNames: string[];
}

/** Business-side summary produced by the LLM in the Map phase. */
export interface BusinessSummary {
    /** The symbol this summary belongs to. */
    symbolName: string;
    /** One-sentence plain-language summary of real side effects. */
    effectSummary: string;
    /** Detected stereotypes (e.g. `<<Service>>`, `<<Repository>>`, `<<Gateway>>`). */
    stereotypes: string[];
    /** Key observations: RPC calls, DB writes, event emissions, etc. */
    sideEffects: string[];
}

/** A single note annotation to attach to a UML element. */
export interface UmlNote {
    /** Which PlantUML element this note attaches to. */
    targetElement: string;
    /** The note body text. */
    content: string;
}

/** Complete output of the ExtractSemanticUML engine. */
export interface SemanticUmlResult {
    /** The generated PlantUML source code (includes stereotypes & notes). */
    plantUml: string;
    /** Structured business summaries per symbol (Map phase output). */
    summaries: BusinessSummary[];
    /** Structured notes embedded in the PlantUML. */
    notes: UmlNote[];
    /** Topology: adjacency list keyed by symbol name -> callee names. */
    callGraph: Map<string, string[]>;
    /** Milliseconds elapsed for the full extraction. */
    elapsedMs: number;
}

// ============================================================================
// 2. Architecture Stitching (Judge) Contracts
// ============================================================================

export type StitchVerdict = 'pass' | 'fail';

/** One specific mismatch between intent and implementation. */
export interface StitchViolation {
    /** Which ArchiMate component is affected. */
    intentComponent: string;
    /** Which code-level element is mismatched. */
    codeElement: string;
    /** Human-readable description of the violation. */
    description: string;
    /** Suggested fix (PlantUML diff or code patch hint). */
    suggestedFix: string;
}

/** Result of a stitching / anti-corruption judgement. */
export interface StitchJudgement {
    verdict: StitchVerdict;
    violations: StitchViolation[];
    /** Full LLM reasoning trace (for debugging / audit). */
    reasoning: string;
}

// ============================================================================
// 3. Traceability Matrix (for /link command)
// ============================================================================

/** One row in the traceability matrix. */
export interface TraceabilityEntry {
    /** ArchiMate component id or name. */
    intentComponent: string;
    /** Mapped code-level classes / modules. */
    codeElements: string[];
    /** Confidence score 0–1. */
    confidence: number;
    /** LLM rationale for the mapping. */
    rationale: string;
}

export interface TraceabilityMatrix {
    entries: TraceabilityEntry[];
    generatedAt: Date;
}

export type DriftSeverity = 'low' | 'medium' | 'high';
export type DriftStatus = 'aligned' | 'minor-drift' | 'major-drift';

export interface ArchitectureDeviation {
    intentComponent: string;
    codeElements: string[];
    category: string;
    severity: DriftSeverity;
    description: string;
    impact: string;
    recommendation: string;
}

export interface ArchitectureDriftReport {
    summary: string;
    overallStatus: DriftStatus;
    driftScore: number;
    deviations: ArchitectureDeviation[];
    recommendations: string[];
    generatedAt: Date;
}

// ============================================================================
// 4. Engine Configuration
// ============================================================================

export interface SemanticUmlEngineOptions {
    /** URI list of files / folders to analyse. */
    targetUris: vscode.Uri[];
    /** If true, run incremental extraction (for /evolve). */
    incremental: boolean;
    /** Optional: only analyse symbols that changed since this git ref. */
    sinceRef?: string;
    /** Max tokens budget per LLM call in Map phase. */
    mapBudgetTokens?: number;
    /** Cancellation support. */
    token: vscode.CancellationToken;
    /** Stream for reporting progress to the chat UI. */
    stream: vscode.ChatResponseStream;
}

